namespace sv_91be0c91732e46b686f54de91cd2a09b.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that tracks the currently selected warehouse for a single circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-a", Name = "Warehouse A" },
        new() { Id = "wh-b", Name = "Warehouse B" },
        new() { Id = "wh-c", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_91be0c91732e46b686f54de91cd2a09b.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies all subscribers
/// when new data arrives. The polling loop lives in the consuming component; this
/// service owns the data fetch and the cross-component notification event.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="RefreshLowStockCountAsync"/> completes.
    /// Subscribers should wrap <c>StateHasChanged</c> in <c>InvokeAsync</c>
    /// because this may fire from a timer thread.
    /// </summary>
    public event Action? OnAlertCountChanged;

    /// <summary>Simulates a database query for items below minimum stock levels.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate latency + random result
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches the latest count for the given warehouse and notifies all subscribers.
    /// Call this from a polling loop or after a warehouse change.
    /// </summary>
    public async Task RefreshLowStockCountAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

