@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard - @Warehouse.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="lead">
    Currently viewing: <strong>@Warehouse.CurrentWarehouseName</strong>
</p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card @(AlertService.LatestLowStockCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.LatestLowStockCount > 5 ? "text-danger" : "text-success")">
                    @AlertService.LatestLowStockCount
                </p>
                <p class="text-muted">
                    Items below minimum level
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <p>
                    <span class="badge bg-info">Live</span>
                    Refreshing every 10 seconds for <strong>@Warehouse.CurrentWarehouseName</strong>
                </p>
                @if (_lastRefresh.HasValue)
                {
                    <p class="text-muted mb-0">
                        Last refreshed: @_lastRefresh.Value.ToString("HH:mm:ss")
                    </p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;
    private Action? _alertHandler;
    private DateTime? _lastRefresh;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe to warehouse changes so we refresh immediately on switch
        _warehouseHandler = () => InvokeAsync(OnWarehouseChangedAsync);
        Warehouse.OnChange += _warehouseHandler;

        // Subscribe to alert changes so this page re-renders when new data arrives
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;

        await StartPollingAsync();
    }

    private async Task OnWarehouseChangedAsync()
    {
        // Restart polling for the new warehouse
        await StopPollingAsync();
        await StartPollingAsync();
        StateHasChanged();
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Initial fetch
        await AlertService.RefreshLowStockCountAsync(Warehouse.CurrentWarehouseId);
        _lastRefresh = DateTime.Now;

        // Background polling loop
        _ = Task.Run(async () =>
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            try
            {
                while (await timer.WaitForNextTickAsync(token))
                {
                    await AlertService.RefreshLowStockCountAsync(Warehouse.CurrentWarehouseId);
                    _lastRefresh = DateTime.Now;
                    // Alert subscribers are notified inside RefreshLowStockCountAsync
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on disposal or warehouse switch
            }
        }, token);
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
        await StopPollingAsync();
    }
}

